mapper.select:
SELECT t.*, u.real_name as user_name, dc.check_name, dc.check_date, p.plan_name FROM check_task_assignments t LEFT JOIN users u ON t.user_id = u.id LEFT JOIN daily_checks dc ON t.daily_check_id = dc.id LEFT JOIN check_plans p ON t.plan_id = p.id WHERE t.user_id = #{userId}
AND t.status = #{status}
AND t.plan_id = #{planId}
ORDER BY t.created_at DESC
